import type { BriefAction, BriefCard, BriefResponse } from "../lib/brief-engine";

export interface BriefExperienceProps {
  brief: BriefResponse;
  moduleName?: string;
}

export function BriefExperience({ brief, moduleName }: BriefExperienceProps) {
  return (
    <section className="ea-brief" aria-label={moduleName ? `${moduleName} brief` : "Brief"}>
      <style>{briefStyles}</style>
      <header className="ea-brief-header">
        <p>{brief.greeting}</p>
        <h1>What needs attention right now</h1>
      </header>

      {brief.topPriority ? (
        <UniversalBriefCard card={brief.topPriority} emphasis="primary" />
      ) : null}

      <section className="ea-brief-section" aria-label="Recommended actions">
        <h2>Recommended Actions</h2>
        <div className="ea-brief-stack">
          {brief.recommendedActions.map((card) => (
            <UniversalBriefCard key={card.id} card={card} />
          ))}
        </div>
      </section>

      <section className="ea-brief-section" aria-label="Today activity">
        <h2>Today&apos;s Activity</h2>
        <ActivityTimeline cards={brief.todaysActivity.length > 0 ? brief.todaysActivity : brief.recentEvents} />
      </section>

      <QuickActions actions={brief.quickActions} />
    </section>
  );
}

export interface UniversalBriefCardProps {
  card: BriefCard;
  emphasis?: "primary" | "default";
}

export function UniversalBriefCard({ card, emphasis = "default" }: UniversalBriefCardProps) {
  const body = (
    <>
      <div>
        <p className="ea-card-kicker">{card.module}</p>
        <h3>{card.title}</h3>
        <p className="ea-card-summary">{card.summary}</p>
      </div>
      <div className="ea-card-footer">
        <span>{card.metric}</span>
        <strong>{card.actionLabel}</strong>
      </div>
    </>
  );

  if (card.actionUrl) {
    return (
      <a className={`ea-brief-card ea-brief-card-${emphasis}`} href={card.actionUrl}>
        {body}
      </a>
    );
  }

  return <article className={`ea-brief-card ea-brief-card-${emphasis}`}>{body}</article>;
}

export function ActivityTimeline({ cards }: { cards: BriefCard[] }) {
  return (
    <ol className="ea-timeline">
      {cards.map((card) => (
        <li key={card.id}>
          <span aria-hidden="true" />
          <div>
            <strong>{card.title}</strong>
            <p>{card.summary}</p>
          </div>
        </li>
      ))}
    </ol>
  );
}

export function QuickActions({ actions }: { actions: BriefAction[] }) {
  if (actions.length === 0) return null;

  return (
    <section className="ea-brief-section" aria-label="Quick actions">
      <h2>Quick Actions</h2>
      <div className="ea-quick-actions">
        {actions.map((action) => (
          <a key={`${action.label}-${action.href}`} href={action.href}>
            {action.label}
          </a>
        ))}
      </div>
    </section>
  );
}

